      bcM = trimmed.match(/^(?:please\s+)?what'?s\s+0b([01]+)\s+in\s+decimal\s*\??\.?$/i);
      if (bcM) return `**${parseInt(bcM[1], 2)}**`;
      bcM = trimmed.match(/^(?:please\s+)?what'?s\s+0x([0-9a-f]+)\s+in\s+decimal\s*\??\.?$/i);
